1	const PROCESSING_FEE = 5;
2	const BASE_PREMIUM_BY_TYPE: Record<string, number> = {
3	  sword: 100,
4	  amulet: 60,
5	  staff: 80,
6	  potion: 40,
7	  rune: 25,
8	  moonstone: 25,
9	};
10	
11	type Item = {
12	  type: string;
13	  cursed?: boolean;
14	  enchantment?: number;
15	  material?: string;
16	};
17	type Customer = { years: number };
18	type Damage = { itemType: string; amount: number };
19	type Incident = { cause: string; damages: Damage[] };
20	type Step = {
21	  type: string;
22	  items?: Item[];
23	  customer?: Customer;
24	  policy?: number;
25	  incident?: Incident;
26	};
27	
28	const BLOCK_OF_3_PRICE = 60;
29	
30	const COMPONENT_TYPES = ["rune", "moonstone"];
31	
32	function countByType(items: Item[]): Record<string, number> {
33	  const counts: Record<string, number> = {};
34	  for (const item of items) {
35	    counts[item.type] = (counts[item.type] ?? 0) + 1;
36	  }
37	  return counts;
38	}
39	
40	function priceForType(type: string, count: number): number {
41	  if (COMPONENT_TYPES.includes(type) && count === 3) {
42	    return BLOCK_OF_3_PRICE;
43	  }
44	  return count * BASE_PREMIUM_BY_TYPE[type];
45	}
46	
47	function isHighlyEnchanted(item: Item): boolean {
48	  return (item.enchantment ?? 0) >= 5;
49	}
50	
51	function hasItemModifier(item: Item): boolean {
52	  return Boolean(item.cursed) || isHighlyEnchanted(item);
53	}
54	
55	const CURSE_SURCHARGE = 0.5;
56	const HIGH_ENCHANTMENT_SURCHARGE = 0.3;
57	
58	function itemSurcharge(item: Item): number {
59	  const base = BASE_PREMIUM_BY_TYPE[item.type];
60	  const curseSurcharge = item.cursed ? base * CURSE_SURCHARGE : 0;
61	  const enchantmentSurcharge = isHighlyEnchanted(item)
62	    ? base * HIGH_ENCHANTMENT_SURCHARGE
63	    : 0;
64	  return curseSurcharge + enchantmentSurcharge;
65	}
66	
67	function modifiedItemsBasePremium(items: Item[]): number {
68	  return items
69	    .filter(hasItemModifier)
70	    .reduce((total, item) => total + BASE_PREMIUM_BY_TYPE[item.type], 0);
71	}
72	
73	function plainPremium(items: Item[]): number {
74	  const counts = countByType(items.filter((item) => !hasItemModifier(item)));
75	  return Object.entries(counts).reduce(
76	    (total, [type, count]) => total + priceForType(type, count),
77	    0,
78	  );
79	}
80	
81	function basePremium(items: Item[]): number {
82	  return modifiedItemsBasePremium(items) + plainPremium(items);
83	}
84	
85	function surchargePremium(items: Item[]): number {
86	  return items.reduce((total, item) => total + itemSurcharge(item), 0);
87	}
88	
89	const LOYALTY_DISCOUNT = 0.2;
90	const LOYALTY_MIN_YEARS = 2;
91	const FIRST_INSURANCE_SURCHARGE = 0.1;
92	const FOLLOW_UP_DISCOUNT = 0.15;
93	
94	function isLoyal(customer: Customer): boolean {
95	  return customer.years >= LOYALTY_MIN_YEARS;
96	}
97	
98	function policyPremium(step: Step, isFollowUp: boolean): number {
99	  const items = step.items ?? [];
100	  const base = basePremium(items);
101	  const surcharges = surchargePremium(items);
102	  if (step.customer === undefined) {
103	    return base + surcharges;
104	  }
105	  const loyaltyDiscount = isLoyal(step.customer) ? LOYALTY_DISCOUNT : 0;
106	  const followUpDiscount = isFollowUp ? FOLLOW_UP_DISCOUNT : 0;
107	  const netModifierRate =
108	    FIRST_INSURANCE_SURCHARGE - loyaltyDiscount - followUpDiscount;
109	  return base + surcharges + base * netModifierRate;
110	}
111	
112	function roundUpInFavor(amount: number): number {
113	  return Math.ceil(amount);
114	}
115	
116	export function runScenario(steps: Step[]): unknown[] {
117	  return steps.map((step, index) => {
118	    const isFollowUp = steps
119	      .slice(0, index)
120	      .some((prior) => prior.type === "quote");
121	    return {
122	      premium: roundUpInFavor(PROCESSING_FEE + policyPremium(step, isFollowUp)),
123	    };
124	  });
125	}
