function roundUpInFavor(amount: number): number {
  return Math.ceil(amount);
}

const DEDUCTIBLE = 100;
const CAP_MULTIPLIER = 2;

function insuranceSum(items: Item[]): number {
  return items.reduce(
    (total, item) => total + INSURANCE_VALUE_BY_TYPE[item.type],
    0,
  );
}

function quoteResult(step: Step, isFollowUp: boolean): { premium: number } {
  return {
    premium: roundUpInFavor(PROCESSING_FEE + policyPremium(step, isFollowUp)),
  };
}

function claimResult(
  step: Step,
  steps: Step[],
): { payout: number; remainingCap: number } {
  const policyStep = steps[step.policy ?? 0];
  const cap = CAP_MULTIPLIER * insuranceSum(policyStep.items ?? []);
  const damages = step.incident?.damages ?? [];
  const payout = damages.reduce(
    (total, damage) => total + (damage.amount - DEDUCTIBLE),
    0,
  );
  return { payout, remainingCap: cap - payout };
}

export function runScenario(steps: Step[]): unknown[] {
  return steps.map((step, index) => {
    if (step.type === "claim") {
      return claimResult(step, steps);
    }
    const isFollowUp = steps
      .slice(0, index)
      .some((prior) => prior.type === "quote");
    return quoteResult(step, isFollowUp);
  });
}
